                long long ni = i + dx;
                long long nj = j + dy;
                if (ni < m && nj < n) {
                    long long entry = (ni + 1) * (nj + 1);
                    long long new_cost = current_cost + entry;
                    if (new_cost < dist[ni][nj][0]) {
                        dist[ni][nj][0] = new_cost;
                        pq.push({new_cost, ni, nj, 0});
                    }
                }
            }
        }
    }
    return -1;
}

