function solve(m, n, waitCost) {
    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.heap.sort((a, b) => a[0] - b[0]);
        }
        pop() {
            if (this.heap.length === 0) return null;
            return this.heap.shift();
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const dist = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dist[i][j] = [Infinity, Infinity];
        }
    }

    dist[0][0][1] = (0 + 1) * (0 + 1);

    const pq = new PriorityQueue();
    pq.push([dist[0][0][1], 0, 0, 1]);

    const directions = [[0, 1], [1, 0]];

    while (!pq.isEmpty()) {
        const [currentCost, i, j, p] = pq.pop();
        if (i === m - 1 && j === n - 1) {
            return currentCost;
        }
        if (currentCost > dist[i][j][p]) {
            continue;
        }
        if (p === 0) {
            const newCost = currentCost + waitCost[i][j];
            if (newCost < dist[i][j][1]) {
                dist[i][j][1] = newCost;
                pq.push([newCost, i, j, 1]);
            }
        } else {
            for (const [dx, dy] of directions) {
                const ni = i + dx;
                const nj = j + dy;
                if (ni < m && nj < n) {
                    const entry = (ni + 1) * (nj + 1);
